#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n; scanf("%d",&n);
        int a[105];
        for(int i=0;i<n;++i) scanf("%d",&a[i]);
        int l=0, r=n-1, val=1;
        int ok=1;
        while(val<=7 && ok){
            if(l>r || a[l]!=val || a[r]!=val){ ok=0; break; }
            int cntL=0, cntR=0;
            while(l<n && a[l]==val){ cntL++; l++; }
            while(r>=0 && a[r]==val){ cntR++; r--; }
            if(cntL!=cntR){ ok=0; break; }
            ++val;
        }
        if(ok && l<=r) ok=0; // leftover elements
        printf("%s\n", ok?"yes":"no");
    }
    return 0;
}

